class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        special = set()
        seen_upper = set()
        for char in word:
            if char.islower() and char.upper() in seen_upper:
                continue
            if char.isupper() and char.lower() in special:
                continue
            if char.islower() and char.upper() in word:
                special.add(char)
            if char.isupper():
                seen_upper.add(char)
        return len(special)
```
